e0b1cb57-42ca-425c-96d8-eaf2738038d0	d72e3909-4494-4f77-8d1c-f07343e32d95	assistant	根据主题检索工具结果，围绕“思乡”这一核心情感，共推荐五首经典诗词，涵盖唐、宋及当代作品，体裁包括五言绝句、七言绝句、词作与新诗风格的近体诗。其中：\n\n- 王加宝《归途》以“暮色连山客路长，一肩风月一肩霜”起笔，凝练勾勒羁旅之艰，结句“却道他乡亦故乡”翻出哲思，在乡愁中透出和解与超越，是当代思乡诗中颇具张力的新声 [1]；  \n- 王维《九月九日忆山东兄弟》以“独在异乡为异客，每逢佳节倍思亲”直击人心，语言质朴而情感浓烈，成为重阳思亲最广为传诵的名句 [2]；  \n- 贺知章《回乡偶书·其一》以“少小离家老大回，乡音无改鬓毛衰”写时空巨变下的身份疏离，“儿童相见不相识，笑问客从何处来”更以童言反衬深沉悲慨，堪称乡愁书写中的人生镜像 [3]；  \n- 柳永《八声甘州·对潇潇暮雨洒江天》以秋日清冷意象铺陈，“不忍登高临远，望故乡渺邈，归思难收”将羁旅之苦与思乡之切熔铸于长调之中，展现宋词深婉绵长的抒情特质 [4]；  \n- 杜甫《月夜忆舍弟》则置于安史之乱背景，“露从今夜白，月是故乡明”以主观诗情重构自然之景，凸显战乱中手足离散、家园难归的沉痛，体现杜诗“以家事写国忧”的厚重境界 [5]。\n\n五首作品时间跨度大、视角各异：或写佳节之思，或写垂老之归，或写乱世之忆，或写秋江之望，或写当代之悟，共同构成中华诗歌中丰富而深沉的“思乡”精神谱系。\n\n```json\n{\n  "title": "思乡主题诗词推荐",\n  "author": ["王加宝", "王维", "贺知章", "柳永", "杜甫"],\n  "dynasty": ["当代", "唐", "唐", "宋", "唐"],\n  "genre": ["七言绝句", "七言绝句", "七言绝句", "词（八声甘州）", "五言律诗"],\n  "theme": "思乡",\n  "famous_lines": [\n    "一肩风月一肩霜，却道他乡亦故乡。",\n    "独在异乡为异客，每逢佳节倍思亲。",\n    "少小离家老大回，乡音无改鬓毛衰。",\n    "不忍登高临远，望故乡渺邈，归思难收。",\n    "露从今夜白，月是故乡明。"\n  ],\n  "appreciation": "王加宝诗以现代语感重构传统羁旅；王维诗以白描见深情；贺知章诗以反讽显苍凉；柳永词以铺叙见层深；杜甫诗以家国同构见沉郁。五者共同拓展了‘思乡’母题的历史纵深与情感维度。"\n}\n```	tool_theme	[{"title": "归途", "author": "王加宝", "snippet": "暮色连山客路长，一肩风月一肩霜。  \\n家山渐近灯初上，却道他乡亦故乡。", "source_file": "归途-王加宝.md"}, {"title": "九月九日忆山东兄弟", "author": "王维", "snippet": "独在异乡为异客，每逢佳节倍思亲。  \\n遥知兄弟登高处，遍插茱萸少一人。", "source_file": "九月九日忆山东兄弟-王维.md"}, {"title": "回乡偶书·其一", "author": "贺知章", "snippet": "少小离家老大回，乡音无改鬓毛衰。  \\n儿童相见不相识，笑问客从何处来。", "source_file": "回乡偶书·其一-贺知章.md"}, {"title": "八声甘州·对潇潇暮雨洒江天", "author": "柳永", "snippet": "对潇潇暮雨洒江天，一番洗清秋。渐霜风凄紧，关河冷落，残照当楼。是处红衰翠减，苒苒物华休。惟有长江水，无语东流。  \\n不忍登高临远，望故乡渺邈，归思难收。叹年来踪", "source_file": "八声甘州·对潇潇暮雨洒江天-柳永.md"}, {"title": "月夜忆舍弟", "author": "杜甫", "snippet": "戍鼓断人行，边秋一雁声。  \\n露从今夜白，月是故乡明。  \\n有弟皆分散，无家问死生。  \\n寄书长不达，况乃未休兵。", "source_file": "月夜忆舍弟-杜甫.md"}]	2026-06-18 03:56:54.130022+00
