bc781467-7db6-4d4a-95d0-029fb6a6bfb1	2b8d7ec3-d271-4d92-bc6c-d3e81a5721ca	assistant	### 字义  \n“渚”为水中的小洲，即水中小块陆地，常见于古典诗词中用以营造空阔、清寂或苍茫的意境 [1][2]。\n\n### 诗例  \n- > 烟渚  \n  此为复合意象，“烟”状薄雾迷蒙之态，“渚”指水中小洲，合指暮霭笼罩下的江中小岛，见于孟浩然《宿建德江》：“移舟泊烟渚，日暮客愁新。”[1]  \n- > 渚  \n  杜甫《登高》中“风急天高猿啸哀，渚清沙白鸟飞回”，“渚清”与“沙白”对举，凸显秋日长江沙洲的澄明萧瑟之景，强化了全诗沉郁悲凉的基调 [2]。\n\n### 小结  \n“渚”虽为地理小词，却因常与“烟”“清”“寒”“孤”等修饰语搭配，成为承载羁旅之思、身世之感与时空苍茫感的重要意象，在盛唐至中唐诗中具有高度的审美凝练性。\n\n```json\n{\n  "title": "渚",\n  "author": "多见于孟浩然、杜甫等诗人作品",\n  "dynasty": "唐代",\n  "genre": "五言律诗、五言绝句",\n  "theme": "羁旅愁思、秋日萧瑟、自然观照",\n  "famous_lines": ["移舟泊烟渚，日暮客愁新", "风急天高猿啸哀，渚清沙白鸟飞回"],\n  "appreciation": "‘渚’作为典型水岸意象，兼具地理实指与诗意虚化功能。\\n其常与视觉氛围词（如‘烟’‘清’）组合，拓展空间纵深与情绪张力。\\n在孟诗中偏重含蓄蕴藉，在杜诗中则融入雄浑悲慨的史诗气质。"\n}\n```	tool_allusion	[{"title": "宿建德江", "snippet": "烟渚：暮霭笼罩的水中小洲。“渚”为水中小块陆地，“烟”状薄雾迷蒙之态。", "source_file": "宿建德江-孟浩然.md"}, {"title": "登高", "snippet": "渚：水中的小洲。", "source_file": "登高-杜甫.md"}]	2026-06-18 14:01:19.302086+00
